{
  "name": "Banana Pro 影像创作中心",
  "description": "基于 Gemini Nano Banana 系列模型的专业级影像处理与创作平台，支持智能修图与参考图重塑。"
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum BananaModel {
  NANO_BANANA = 'gemini-2.5-flash-image',
  NANO_BANANA_PRO = 'gemini-3-pro-image-preview',
}

export enum AspectRatio {
  SQUARE = '1:1',
  PORTRAIT_3_4 = '3:4',
  PORTRAIT_4_5 = '4:5',
  PORTRAIT_9_16 = '9:16',
  LANDSCAPE_16_9 = '16:9',
}

export enum ImageResolution {
  RES_1K = '1K',
  RES_2K = '2K',
  RES_4K = '4K',
}

export interface GeneratedImage {
  url: string;
  seed?: number;
}

export interface GenerationError {
  message: string;
  details?: string;
}

// Augment window for AI Studio key selection
declare global {
  interface Window {
    aistudio?: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

import { GoogleGenAI, Type } from "@google/genai";
import { BananaModel, AspectRatio, ImageResolution } from "../types";

// Helper to ensure API Key is ready, especially for Pro models
const getClient = async (model: BananaModel): Promise<GoogleGenAI> => {
  if (model === BananaModel.NANO_BANANA_PRO) {
    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
      }
    }
  }

  // Create a new instance to ensure we pick up the latest key/env
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

const extractImagesFromResponse = (response: any): string[] => {
  const images: string[] = [];

  if (!response.candidates || response.candidates.length === 0) {
    return images;
  }

  for (const candidate of response.candidates) {
    if (candidate.content && candidate.content.parts) {
      for (const part of candidate.content.parts) {
        if (part.inlineData) {
          const mimeType = part.inlineData.mimeType || 'image/png';
          const base64 = part.inlineData.data;
          images.push(`data:${mimeType};base64,${base64}`);
        }
      }
    }
  }
  return images;
};

interface EditImageParams {
  model: BananaModel;
  imageBase64: string; // The original image
  maskBase64?: string; // The drawn mask (optional)
  prompt: string;
  aspectRatio: AspectRatio;
}

export const editImageWithGemini = async ({
  model,
  imageBase64,
  maskBase64,
  prompt,
  aspectRatio
}: EditImageParams): Promise<string[]> => {
  const ai = await getClient(model);

  // Clean base64 strings
  const cleanImage = imageBase64.replace(/^data:image\/\w+;base64,/, "");

  const parts: any[] = [
    {
      inlineData: {
        data: cleanImage,
        mimeType: "image/png",
      },
    }
  ];

  // If a mask is provided, we add it as a second image part and instruct the model
  let finalPrompt = prompt;
  if (maskBase64) {
    const cleanMask = maskBase64.replace(/^data:image\/\w+;base64,/, "");
    parts.push({
      inlineData: {
        data: cleanMask,
        mimeType: "image/png",
      }
    });
    // Append instruction to use the second image as mask
    finalPrompt = `${prompt}. (注意：第二张图片是蒙版/Mask，请只针对蒙版覆盖的白色区域进行编辑或重绘，保持其他区域不变)`;
  }

  parts.push({ text: finalPrompt });

  const config: any = {
    imageConfig: {
      aspectRatio: aspectRatio,
    }
  };

  // Only Pro supports resolution config
  if (model === BananaModel.NANO_BANANA_PRO) {
     config.imageConfig.imageSize = "1K"; // Defaulting to 1K for edit for speed
  }

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: { parts },
      config: config
    });

    return extractImagesFromResponse(response);
  } catch (error: any) {
    console.error("Edit Image Error:", error);
    throw new Error(error.message || "图像编辑请求失败");
  }
};

interface RecreateImageParams {
  model: BananaModel;
  referenceImageBase64: string;
  prompt: string;
  aspectRatio: AspectRatio;
  numberOfImages: number;
  quality: ImageResolution;
}

export const recreateImageWithGemini = async ({
  model,
  referenceImageBase64,
  prompt,
  aspectRatio,
  numberOfImages,
  quality
}: RecreateImageParams): Promise<string[]> => {
  const ai = await getClient(model);
  const cleanRef = referenceImageBase64.replace(/^data:image\/\w+;base64,/, "");

  // Critical: Construct payload with both image and text for "Image Variation/Recreation"
  // The user prompt specifically asked to ensure this logic is correct.
  const parts = [
    {
      inlineData: {
        data: cleanRef,
        mimeType: "image/png", // Assuming PNG, can detect if needed but PNG is safe for canvas exports
      },
    },
    {
      text: `基于提供的参考图，请按照以下要求生成新的图像：${prompt}`,
    },
  ];

  const config: any = {
    imageConfig: {
      aspectRatio: aspectRatio,
      // count parameter is not directly supported in generateContent for 'numberOfImages' in all SDK versions/models similarly to Imagen.
      // However, for generateContent, usually 1 request = 1 candidate unless specified. 
      // The prompt asks for 1-4 images. For Gemini models via generateContent, we often need multiple requests or `candidateCount` (which is often limited to 1 for images).
      // We will loop in the UI if needed, OR relies on the model returning multiple candidates if supported. 
      // Current Gemini 2.5/3 specs for image generation suggest single output per request usually.
      // We will set imageSize if Pro.
    }
  };

  if (model === BananaModel.NANO_BANANA_PRO) {
    config.imageConfig.imageSize = quality;
  }

  try {
    // To support "numberOfImages" which might not be native to single generateContent call for images yet:
    // We will execute parallel requests if count > 1.
    const promises = Array.from({ length: numberOfImages }).map(() => 
      ai.models.generateContent({
        model: model,
        contents: { parts },
        config: config
      })
    );

    const responses = await Promise.all(promises);

    let allImages: string[] = [];
    responses.forEach(res => {
      allImages = [...allImages, ...extractImagesFromResponse(res)];
    });

    if (allImages.length === 0) {
      throw new Error("模型未返回任何图像数据，请检查提示词是否触犯安全限制。");
    }

    return allImages;

  } catch (error: any) {
    console.error("Recreate Image Error:", error);
    throw new Error(error.message || "重塑创作请求失败");
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  disabled,
  ...props 
}) => {
  const baseStyle = "px-4 py-2 rounded-lg font-medium transition-all duration-200 flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-yellow-500 hover:bg-yellow-400 text-gray-900",
    secondary: "bg-gray-700 hover:bg-gray-600 text-white",
    danger: "bg-red-600 hover:bg-red-700 text-white shadow-lg shadow-red-900/20",
    ghost: "bg-transparent hover:bg-gray-800 text-gray-400 hover:text-white"
  };

  return (
    <button 
      className={`${baseStyle} ${variants[variant]} ${className}`}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading ? (
        <>
          <svg className="animate-spin h-5 w-5 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          <span>处理中...</span>
        </>
      ) : children}
    </button>
  );
};

import React from 'react';

