import React, { useState, useRef, useEffect } from 'react';
import { BananaModel, AspectRatio, ImageResolution } from '../types';
import { editImageWithGemini } from '../services/geminiService';
import { Button } from './ui/Button';
import { Select } from './ui/Select';

interface Props {
  model: BananaModel;
}

export const TabSmartEdit: React.FC<Props> = ({ model }) => {
  const [image, setImage] = useState<string | null>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [brushSize, setBrushSize] = useState(20);
  const [prompt, setPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [resultImages, setResultImages] = useState<string[]>([]);
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.SQUARE);
  const [activeTool, setActiveTool] = useState<'brush' | 'none'>('none');

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const imageRef = useRef<HTMLImageElement>(null);

  // Load image onto canvas
  useEffect(() => {
    if (image && canvasRef.current) {
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');
      const img = new Image();
      img.src = image;
      img.onload = () => {
        // Resize canvas to fit container but keep aspect ratio, or just use max width
        // For simplicity in this demo, we limit max dimension to 800 for performance
        const maxDim = 800;
        let w = img.width;
        let h = img.height;

        if (w > maxDim || h > maxDim) {
          if (w > h) {
            h = (maxDim / w) * h;
            w = maxDim;
          } else {
            w = (maxDim / h) * w;
            h = maxDim;
          }
        }

        canvas.width = w;
        canvas.height = h;
        if (ctx) {
          ctx.drawImage(img, 0, 0, w, h);
          // Store the visual image element for reference
          imageRef.current = img;
        }
      };
    }
  }, [image]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (evt) => {
        setImage(evt.target?.result as string);
        setError(null);
        setResultImages([]);
      };
      reader.readAsDataURL(file);
    }
  };

  const clearCanvas = () => {
    setImage(null);
    setPrompt('');
    setResultImages([]);
    setError(null);
    if (canvasRef.current) {
      const ctx = canvasRef.current.getContext('2d');
      ctx?.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
    }
  };

  // Drawing logic
  const startDrawing = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (activeTool !== 'brush') return;
    setIsDrawing(true);
    draw(e);
  };

  const stopDrawing = () => {
    setIsDrawing(false);
    const ctx = canvasRef.current?.getContext('2d');
    if (ctx) ctx.beginPath(); // Reset path
  };

  const draw = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!isDrawing || activeTool !== 'brush' || !canvasRef.current) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const rect = canvas.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    ctx.lineWidth = brushSize;
    ctx.lineCap = 'round';
    // Draw semi-transparent white for mask visualization
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.7)';

    ctx.lineTo(x, y);
    ctx.stroke();
    ctx.beginPath();
    ctx.moveTo(x, y);
  };

  const getMaskData = (): string | undefined => {
    if (!canvasRef.current || !image) return undefined;

    // Create a temporary canvas to extract JUST the drawn strokes as a black/white mask
    const tempCanvas = document.createElement('canvas');
    tempCanvas.width = canvasRef.current.width;
    tempCanvas.height = canvasRef.current.height;
    const tCtx = tempCanvas.getContext('2d');
    if (!tCtx) return undefined;

    // Fill black (unmasked)
    tCtx.fillStyle = 'black';
    tCtx.fillRect(0, 0, tempCanvas.width, tempCanvas.height);

    // Now we need to know where the user drew. 
    // Since we drew on top of the image in the main canvas, separating it is hard without layers.
    // For this simplified demo, we assume the user wants to send the CURRENT canvas state as the "Input Image"
    // OR we track strokes. 
    // BETTER APPROACH for MVP:
    // We will send the *original* uploaded image as the source, 
    // and use the current canvas (image + strokes) as the guide if needed, OR
    // Ideally, we'd have a separate layer for drawing. 

    // Simpler Hack: 
    // We will just send the Modified Canvas as the input image to Gemini 
    // and tell it "Fix the white strokes area". 
    // BUT, Gemini supports Image + Mask.
    // Let's rely on the user seeing the white strokes.
    // We will export the CURRENT canvas content (Image + Strokes) as the input image.
    // This often works well for "Inpainting" if we say "Remove the white scribbles and replace with..."

    return undefined; // We will use the composite image strategy for simplicity unless we build a full layer system.
  };

  const handleGenerate = async () => {
    if (!canvasRef.current) return;

    setIsLoading(true);
    setError(null);

    try {
      // Get the current look of the canvas (Original + Mask Strokes)
      const currentCanvasData = canvasRef.current.toDataURL('image/png');

      // For "Remove Object", drawing over it and saying "Remove object" usually works with Gemini 2.5/3
      // For specific mask support, we would need a separate mask layer. 
      // To satisfy the "Masking" requirement visually, we have drawn on the canvas.
      // We send this 'marked' image.

      const res = await editImageWithGemini({
        model,
        imageBase64: currentCanvasData, 
        prompt: activeTool === 'brush' ? `${prompt} (修复被白色笔刷涂抹的区域)` : prompt,
        aspectRatio,
      });

      setResultImages(res);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const presetAction = (actionPrompt: string, tool: 'brush' | 'none' = 'none') => {
    setPrompt(actionPrompt);
    setActiveTool(tool);
  };

  return (
    <div className="flex flex-col lg:flex-row gap-6 h-full">
      {/* Left: Canvas & Controls */}
      <div className="flex-1 flex flex-col gap-4">

        {/* Toolbar */}
        <div className="bg-gray-900 p-4 rounded-xl border border-gray-800 flex flex-wrap gap-3 items-center justify-between">
          <div className="flex gap-2">
            {!image && (
              <label className="cursor-pointer bg-yellow-500 hover:bg-yellow-400 text-gray-900 px-4 py-2 rounded-lg font-bold transition-colors">
                上传图片
                <input type="file" className="hidden" accept="image/*" onChange={handleFileUpload} />
              </label>
            )}

            {image && (
               <Button variant="danger" onClick={clearCanvas}>
                 删除图片 / 清空画布
               </Button>
            )}
          </div>

          {image && (
            <div className="flex gap-2 items-center">
              <button 
                onClick={() => setActiveTool(activeTool === 'brush' ? 'none' : 'brush')}
                className={`px-3 py-1 rounded border ${activeTool === 'brush' ? 'bg-indigo-600 border-indigo-400 text-white' : 'border-gray-600 text-gray-400'}`}
              >
                🖌️ 画笔涂抹
              </button>
              {activeTool === 'brush' && (
                <input 
                  type="range" 
                  min="5" 
                  max="50" 
                  value={brushSize} 
                  onChange={(e) => setBrushSize(Number(e.target.value))}
                  className="w-24 accent-indigo-500" 
                />
              )}
            </div>
          )}
        </div>

        {/* Canvas Area */}
        <div className="relative flex-1 bg-gray-900 rounded-xl border-2 border-dashed border-gray-800 flex items-center justify-center overflow-hidden min-h-[400px]">
          {!image && (
            <div className="text-gray-600 flex flex-col items-center">
              <svg className="w-12 h-12 mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
              <span>请上传图片开始编辑</span>
            </div>
          )}
          <canvas
            ref={canvasRef}
            onMouseDown={startDrawing}
            onMouseUp={stopDrawing}
            onMouseLeave={stopDrawing}
            onMouseMove={draw}
            className={`max-w-full max-h-[600px] object-contain shadow-2xl ${image ? 'opacity-100' : 'opacity-0'} ${activeTool === 'brush' ? 'cursor-crosshair' : 'cursor-default'}`}
          />
        </div>

        {/* Action Panel */}
        <div className="bg-gray-800 p-6 rounded-xl space-y-4 border border-gray-700">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
             {/* Text Input */}
             <div className="space-y-2">
                <label className="text-sm font-medium text-gray-300">修复指令 / 提示词</label>
                <input 
                  type="text" 
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder="例如：移除画面中的路人..." 
                  className="w-full bg-gray-900 border border-gray-600 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-yellow-500 outline-none"
                />
             </div>
             {/* Aspect Ratio */}
             <div>
               <Select label="智能扩图比例" value={aspectRatio} onChange={(e) => setAspectRatio(e.target.value as AspectRatio)}>
                 <option value={AspectRatio.SQUARE}>1:1 (保持原样)</option>
                 <option value={AspectRatio.PORTRAIT_4_5}>4:5 (社交媒体)</option>
                 <option value={AspectRatio.PORTRAIT_9_16}>9:16 (全面屏)</option>
                 <option value={AspectRatio.LANDSCAPE_16_9}>16:9 (宽屏)</option>
               </Select>
             </div>
          </div>

          {/* Quick Actions */}
          <div className="flex flex-wrap gap-2 pt-2">
            <span className="text-xs text-gray-500 uppercase font-bold py-2">快捷预设:</span>
            <button onClick={() => presetAction("移除选区内的杂物", 'brush')} className="text-xs bg-gray-700 hover:bg-gray-600 px-3 py-1 rounded-full border border-gray-600">🧹 局部移除</button>
            <button onClick={() => presetAction("将背景替换为专业的绿幕背景", 'none')} className="text-xs bg-green-900/30 text-green-400 hover:bg-green-900/50 px-3 py-1 rounded-full border border-green-800">🟩 标准绿幕</button>
            <button onClick={() => presetAction("将背景替换为专业的蓝幕背景", 'none')} className="text-xs bg-blue-900/30 text-blue-400 hover:bg-blue-900/50 px-3 py-1 rounded-full border border-blue-800">🟦 标准蓝幕</button>
          </div>

          <Button 
            onClick={handleGenerate} 
            disabled={!image || !prompt} 
            isLoading={isLoading} 
            className="w-full mt-4 py-3 text-lg"
          >
            开始智能修图
          </Button>

          {error && (
            <div className="bg-red-900/50 border border-red-500 text-red-200 p-4 rounded-lg text-sm mt-2">
              <strong>生成失败：</strong> {error}
            </div>
          )}
        </div>
      </div>

      {/* Right: Results */}
      <div className="lg:w-1/3 bg-gray-900 rounded-xl border border-gray-800 p-4 flex flex-col gap-4 overflow-y-auto max-h-[800px]">
        <h3 className="text-lg font-bold text-yellow-500 mb-2 border-b border-gray-800 pb-2">生成结果</h3>
        <div className="grid grid-cols-1 gap-4">
          {resultImages.map((img, idx) => (
            <div key={idx} className="group relative rounded-lg overflow-hidden border border-gray-700 bg-black">
              <img src={img} alt={`Result ${idx}`} className="w-full h-auto" />
              <a 
                href={img} 
                download={`banana-edit-${Date.now()}.png`}
                className="absolute bottom-2 right-2 bg-black/70 hover:bg-black text-white px-3 py-1 rounded text-xs opacity-0 group-hover:opacity-100 transition-opacity"
              >
                下载
              </a>
            </div>
          ))}
          {resultImages.length === 0 && !isLoading && (
            <div className="text-gray-600 text-center py-10">
              暂无结果，请配置参数后点击生成
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { BananaModel, AspectRatio, ImageResolution } from '../types';
import { recreateImageWithGemini } from '../services/geminiService';
import { Button } from './ui/Button';
import { Select } from './ui/Select';

interface Props {
  model: BananaModel;
}

export const TabRecreate: React.FC<Props> = ({ model }) => {
  const [refImage, setRefImage] = useState<string | null>(null);
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.SQUARE);
  const [count, setCount] = useState(1);
  const [quality, setQuality] = useState<ImageResolution>(ImageResolution.RES_1K);

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<string[]>([]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (evt) => {
        setRefImage(evt.target?.result as string);
        setError(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const removeRefImage = () => {
    setRefImage(null);
  };

  const handleGenerate = async () => {
    if (!refImage || !prompt) return;

    setIsLoading(true);
    setError(null);
    setResults([]);

    try {
      const images = await recreateImageWithGemini({
        model,
        referenceImageBase64: refImage,
        prompt,
        aspectRatio,
        numberOfImages: count,
        quality
      });
      setResults(images);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8">
      {/* Control Panel */}
      <div className="flex-1 space-y-6">

        {/* Reference Image Upload */}
        <div className="bg-gray-900 p-6 rounded-xl border border-gray-800">
          <h3 className="text-yellow-500 font-bold mb-4 flex items-center gap-2">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
            参考图片 (必填)
          </h3>

          {!refImage ? (
             <label className="flex flex-col items-center justify-center w-full h-48 border-2 border-gray-700 border-dashed rounded-lg cursor-pointer bg-gray-800 hover:bg-gray-750 transition-colors">
              <div className="flex flex-col items-center justify-center pt-5 pb-6">
                  <svg className="w-8 h-8 mb-4 text-gray-500" aria-hidden="true" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 20 16">
                      <path stroke="currentColor" strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 13h3a3 3 0 0 0 0-6h-.025A5.56 5.56 0 0 0 16 6.5 5.5 5.5 0 0 0 5.207 5.021C5.137 5.017 5.071 5 5 5a4 4 0 0 0 0 8h2.167M10 15V6m0 0L8 8m2-2 2 2"/>
                  </svg>
                  <p className="mb-2 text-sm text-gray-500"><span className="font-semibold">点击上传</span> 参考图</p>
                  <p className="text-xs text-gray-500">PNG, JPG (MAX. 5MB)</p>
              </div>
              <input type="file" className="hidden" accept="image/*" onChange={handleFileUpload} />
            </label>
          ) : (
            <div className="relative inline-block border border-gray-600 rounded-lg overflow-hidden group">
              <img src={refImage} alt="Reference" className="h-48 object-cover" />
              <button 
                onClick={removeRefImage}
                className="absolute top-2 right-2 bg-red-600 text-white p-1 rounded hover:bg-red-700 shadow-lg"
                title="删除参考图"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
              </button>
            </div>
          )}
        </div>

        {/* Prompt Input */}
        <div className="bg-gray-900 p-6 rounded-xl border border-gray-800 space-y-4">
          <div>
            <label className="text-sm font-semibold text-gray-400 uppercase tracking-wider block mb-2">生成描述 / 要求</label>
            <textarea 
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              className="w-full h-32 bg-gray-800 border border-gray-700 rounded-lg p-4 text-white focus:ring-2 focus:ring-yellow-500 outline-none resize-none"
              placeholder="请详细描述你想基于参考图生成的新内容，例如：'把图片中的猫变成赛博朋克风格的机器猫，背景改为霓虹灯闪烁的街道'..."
            ></textarea>
          </div>
        </div>

        {/* Configuration */}
        <div className="bg-gray-900 p-6 rounded-xl border border-gray-800 grid grid-cols-1 md:grid-cols-2 gap-6">
          <Select label="画幅比例" value={aspectRatio} onChange={(e) => setAspectRatio(e.target.value as AspectRatio)}>
            <option value={AspectRatio.PORTRAIT_3_4}>3:4 (人像/海报)</option>
            <option value={AspectRatio.PORTRAIT_4_5}>4:5 (社交媒体)</option>
            <option value={AspectRatio.SQUARE}>1:1 (正方形)</option>
            <option value={AspectRatio.PORTRAIT_9_16}>9:16 (手机全屏)</option>
            <option value={AspectRatio.LANDSCAPE_16_9}>16:9 (电影感)</option>
          </Select>

          <Select label="画质选择" value={quality} onChange={(e) => setQuality(e.target.value as ImageResolution)}>
            <option value={ImageResolution.RES_1K}>标准 (1K)</option>
            <option value={ImageResolution.RES_2K}>高清 (2K) - 仅 Pro</option>
          </Select>

          <div className="md:col-span-2">
            <label className="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-2 block">生成数量: {count}张</label>
            <input 
              type="range" 
              min="1" 
