import React, { useState, useRef, useEffect } from 'react';
import { BananaModel, AspectRatio, ImageResolution } from '../types';
import { editImageWithGemini } from '../services/geminiService';
import { Button } from './ui/Button';
import { Select } from './ui/Select';

interface Props {
  model: BananaModel;
}

export const TabSmartEdit: React.FC<Props> = ({ model }) => {
  const [image, setImage] = useState<string | null>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [brushSize, setBrushSize] = useState(20);
  const [prompt, setPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [resultImages, setResultImages] = useState<string[]>([]);

  // Default to ORIGINAL to respect uploaded image dimensions
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.ORIGINAL);
  const [activeTool, setActiveTool] = useState<'brush' | 'eraser' | 'none'>('none');
  const [isDragging, setIsDragging] = useState(false);

  // History for Undo
  const [history, setHistory] = useState<ImageData[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const imageRef = useRef<HTMLImageElement>(null);

  // Load image onto canvas
  useEffect(() => {
    if (image && canvasRef.current) {
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');
      const img = new Image();
      img.src = image;
      img.onload = () => {
        // Limit max resolution for performance, but KEEP ASPECT RATIO EXACTLY
        const maxDim = 1500; 
        let w = img.width;
        let h = img.height;

        if (w > maxDim || h > maxDim) {
          const ratio = w / h;
          if (w > h) {
            w = maxDim;
            h = maxDim / ratio;
          } else {
            h = maxDim;
            w = maxDim * ratio;
          }
        }

        // Set internal resolution to match image (scaled)
        canvas.width = w;
        canvas.height = h;

        if (ctx) {
          ctx.lineCap = 'round';
          ctx.lineJoin = 'round';
          ctx.drawImage(img, 0, 0, w, h);
          imageRef.current = img;
          // Clear history on new image load
          setHistory([]); 
          saveToHistory(); 
        }
      };
    }
  }, [image]);

  const saveToHistory = () => {
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (canvas && ctx) {
      const data = ctx.getImageData(0, 0, canvas.width, canvas.height);
      setHistory(prev => {
        const newHist = [...prev, data];
        // Keep last 10 steps
        if (newHist.length > 10) return newHist.slice(newHist.length - 10);
        return newHist;
      });
    }
  };

  const undo = () => {
    if (history.length <= 1) return; // Keep initial state
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (canvas && ctx) {
      const newHistory = [...history];
      newHistory.pop(); // Remove current state
      const previousState = newHistory[newHistory.length - 1];
      ctx.putImageData(previousState, 0, 0);
      setHistory(newHistory);
    }
  };

  const validateAndSetImage = (file: File) => {
    if (file.size > 10 * 1024 * 1024) {
       setError("文件大小不能超过 10MB");
       return;
    }
    const reader = new FileReader();
    reader.onload = (evt) => {
      setImage(evt.target?.result as string);
      setError(null);
      setResultImages([]);
      setHistory([]);
    };
    reader.readAsDataURL(file);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) validateAndSetImage(file);
  };

  // Drag & Drop Handlers
  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };
  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };
  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files?.[0];
    if (file && file.type.startsWith('image/')) {
      validateAndSetImage(file);
    }
  };

  const clearCanvas = () => {
    setImage(null);
    setPrompt('');
    setResultImages([]);
    setError(null);
    setHistory([]);
    if (canvasRef.current) {
      const ctx = canvasRef.current.getContext('2d');
      ctx?.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
    }
  };

  // Drawing logic
  const getCoordinates = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };

    const rect = canvas.getBoundingClientRect();
    // CRITICAL: Calculate scale factor to map displayed size to internal resolution
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;

    return {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY
    };
  };

  const startDrawing = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (activeTool === 'none') return;
    setIsDrawing(true);
    const { x, y } = getCoordinates(e);

    const ctx = canvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.beginPath();
      ctx.moveTo(x, y);
      draw(e); // Draw single dot if click
    }
  };

  const stopDrawing = () => {
    if (isDrawing) {
      setIsDrawing(false);
      const ctx = canvasRef.current?.getContext('2d');
      if (ctx) {
         ctx.beginPath();
         saveToHistory(); // Save state after stroke
      }
    }
  };

  const draw = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!isDrawing || activeTool === 'none' || !canvasRef.current) return;

    const ctx = canvasRef.current.getContext('2d');
    if (!ctx) return;

    const { x, y } = getCoordinates(e);

    ctx.lineWidth = brushSize;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    if (activeTool === 'eraser') {
      ctx.globalCompositeOperation = 'destination-out'; // Erase
      // Make eraser slightly bigger for usability? No, keep consistant.
      ctx.strokeStyle = 'rgba(0,0,0,1)';
    } else {
      ctx.globalCompositeOperation = 'source-over'; // Draw
      ctx.strokeStyle = 'rgba(255, 255, 255, 0.8)';
    }

    ctx.lineTo(x, y);
    ctx.stroke();
    // Don't reset path here for smooth curves, only reset on stopDrawing or startDrawing
  };

  const getCalculatedAspectRatio = (model: BananaModel): AspectRatio => {
    if (aspectRatio !== AspectRatio.ORIGINAL) return aspectRatio;

    if (!canvasRef.current) return AspectRatio.SQUARE;

    const w = canvasRef.current.width;
    const h = canvasRef.current.height;
    const ratio = w / h;

    // Find closest standard ratio
    if (ratio > 1.6) return AspectRatio.LANDSCAPE_16_9; // ~1.77
    if (ratio > 1.2) return AspectRatio.SQUARE; // 4:3 is ~1.33, but 1:1 is safe default if not explicitly 4:3 supported by enum
    if (ratio > 0.9) return AspectRatio.SQUARE;
    if (ratio > 0.7) return AspectRatio.PORTRAIT_3_4; // 0.75
    if (ratio > 0.6) return AspectRatio.PORTRAIT_9_16; // 0.56

    return AspectRatio.SQUARE;
  };

  const handleGenerate = async () => {
    if (!canvasRef.current) return;

    setIsLoading(true);
    setError(null);

    try {
      const currentCanvasData = canvasRef.current.toDataURL('image/png');
      const finalAspectRatio = getCalculatedAspectRatio(model);

      const res = await editImageWithGemini({
        model,
        imageBase64: currentCanvasData, 
        prompt: (activeTool === 'brush' || activeTool === 'eraser') ? `${prompt} (修复被白色笔刷涂抹的区域)` : prompt,
        aspectRatio: finalAspectRatio,
      });

      setResultImages(res);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const presetAction = (actionPrompt: string, tool: 'brush' | 'none' = 'none') => {
    setPrompt(actionPrompt);
    if (tool !== 'none') setActiveTool(tool);
  };

  return (
    <div className="flex flex-col lg:flex-row gap-6 h-full">
      {/* Left: Canvas & Controls */}
      <div className="flex-1 flex flex-col gap-4">

        {/* Toolbar */}
        <div className="bg-gray-900 p-4 rounded-xl border border-gray-800 flex flex-wrap gap-3 items-center justify-between">
          <div className="flex gap-2">
            {!image && (
              <label className="cursor-pointer bg-yellow-500 hover:bg-yellow-400 text-gray-900 px-4 py-2 rounded-lg font-bold transition-colors">
                上传图片
                <input type="file" className="hidden" accept="image/*" onChange={handleFileUpload} />
              </label>
            )}

            {image && (
               <Button variant="danger" onClick={clearCanvas}>
                 删除图片 / 清空画布
               </Button>
            )}
          </div>

          {image && (
            <div className="flex gap-2 items-center flex-wrap">
              <div className="flex bg-gray-800 rounded-lg p-1 border border-gray-700">
                <button 
                  onClick={() => setActiveTool(activeTool === 'brush' ? 'none' : 'brush')}
                  className={`px-3 py-1.5 rounded text-sm font-medium transition-colors ${activeTool === 'brush' ? 'bg-indigo-600 text-white' : 'text-gray-400 hover:text-white'}`}
                  title="画笔"
                >
                  🖌️ 涂抹
                </button>
                <button 
                  onClick={() => setActiveTool(activeTool === 'eraser' ? 'none' : 'eraser')}
                  className={`px-3 py-1.5 rounded text-sm font-medium transition-colors ${activeTool === 'eraser' ? 'bg-pink-600 text-white' : 'text-gray-400 hover:text-white'}`}
                  title="橡皮擦"
                >
                  🧽 擦除
                </button>
              </div>

              <div className="border-l border-gray-700 mx-2 h-6"></div>

              <button 
                onClick={undo}
                disabled={history.length <= 1}
                className="px-3 py-1.5 bg-gray-800 hover:bg-gray-700 disabled:opacity-30 disabled:cursor-not-allowed border border-gray-700 rounded text-gray-300 text-sm"
                title="撤销"
              >
