            onMouseDown={startDrawing}
            onMouseUp={stopDrawing}
            onMouseLeave={stopDrawing}
            onMouseMove={draw}
            className={`max-w-full max-h-[600px] object-contain shadow-2xl ${image ? 'opacity-100' : 'opacity-0'} 
              ${activeTool === 'brush' ? 'cursor-crosshair' : activeTool === 'eraser' ? 'cursor-cell' : 'cursor-default'}
            `}
            style={{
               // Ensure css dimensions don't distort internal resolution
               width: 'auto',
               height: 'auto'
            }}
          />
        </div>

        {/* Action Panel */}
        <div className="bg-gray-800 p-6 rounded-xl space-y-4 border border-gray-700">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
             {/* Text Input */}
             <div className="space-y-2">
                <label className="text-sm font-medium text-gray-300">修复指令 / 提示词</label>
                <input 
                  type="text" 
                  value={prompt}
