            {/* New Clean Button */}
            <Button 
                onClick={handleCleanImage} 
                disabled={!image} 
                isLoading={isLoading} 
                variant="secondary"
                className="flex-1 py-3 text-lg border border-gray-600 bg-gray-800 hover:bg-gray-700 text-yellow-500"
              >
                🧼 一键清理 / 重绘
            </Button>
          </div>

          {/* Preset Chips */}
          <div className="flex flex-wrap gap-2 pt-2 border-t border-gray-700 mt-2">
            <span className="text-xs text-gray-500 uppercase font-bold py-1">预设指令:</span>
