};

import React, { useState } from 'react';
import { BananaModel, AspectRatio, ImageResolution } from '../types';
import { recreateImageWithGemini } from '../services/geminiService';
import { Button } from './ui/Button';
import { Select } from './ui/Select';

interface Props {
  model: BananaModel;
}

export const TabRecreate: React.FC<Props> = ({ model }) => {
  const [refImage, setRefImage] = useState<string | null>(null);
  const [imageDimensions, setImageDimensions] = useState<{width: number, height: number} | null>(null);

  const [prompt, setPrompt] = useState('');
  const [textPrompt, setTextPrompt] = useState(''); // New state for overlay text

  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.ORIGINAL);
  const [count, setCount] = useState(1);
  const [quality, setQuality] = useState<ImageResolution>(ImageResolution.RES_1K);

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<string[]>([]);
  const [isDragging, setIsDragging] = useState(false);

  const validateAndSetImage = (file: File) => {
    if (file.size > 10 * 1024 * 1024) {
      setError("文件大小不能超过 10MB");
      return;
    }
    const reader = new FileReader();
    reader.onload = (evt) => {
      const src = evt.target?.result as string;
      setRefImage(src);
      setError(null);
      // Load image to get dimensions
      const img = new Image();
      img.src = src;
      img.onload = () => {
        setImageDimensions({ width: img.width, height: img.height });
      };
    };
    reader.readAsDataURL(file);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) validateAndSetImage(file);
  };

  // Drag & Drop Handlers
  const handleDragOver = (e: React.DragEvent) => { e.preventDefault(); setIsDragging(true); };
  const handleDragLeave = (e: React.DragEvent) => { e.preventDefault(); setIsDragging(false); };
  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files?.[0];
    if (file && file.type.startsWith('image/')) {
      validateAndSetImage(file);
    }
  };

  const removeRefImage = () => {
    setRefImage(null);
    setImageDimensions(null);
  };

  const getCalculatedAspectRatio = (model: BananaModel): AspectRatio => {
    if (aspectRatio !== AspectRatio.ORIGINAL) return aspectRatio;
    if (!imageDimensions) return AspectRatio.SQUARE;

    const currentRatio = imageDimensions.width / imageDimensions.height;

    // Supported Ratios
    const supported = [
      { id: AspectRatio.SQUARE, val: 1.0 },
      { id: AspectRatio.PORTRAIT_3_4, val: 0.75 },
      { id: AspectRatio.PORTRAIT_4_5, val: 0.8 },
      { id: AspectRatio.PORTRAIT_9_16, val: 0.5625 },
      { id: AspectRatio.LANDSCAPE_16_9, val: 1.777 },
    ];

    const closest = supported.reduce((prev, curr) => {
      return (Math.abs(curr.val - currentRatio) < Math.abs(prev.val - currentRatio) ? curr : prev);
    });

    return closest.id;
  };

  const handleGenerate = async () => {
    if (!refImage || (!prompt && !textPrompt)) return;

    setIsLoading(true);
    setError(null);
    setResults([]);

    try {
      const finalAspectRatio = getCalculatedAspectRatio(model);

      let finalPrompt = prompt;

      // Merge logic if text content is provided
      if (textPrompt) {
        finalPrompt = `${prompt ? prompt + "\n\n" : ""}ADDITIONAL TASK: Add or Replace text in the image. \nText Content to render: "${textPrompt}". \nEnsure the typography matches the image style.`;
      }

      const images = await recreateImageWithGemini({
        model,
        referenceImageBase64: refImage,
        prompt: finalPrompt,
        aspectRatio: finalAspectRatio,
        numberOfImages: count,
        quality
      });
      setResults(images);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8 h-full">
      {/* Control Panel */}
      <div className="flex-1 space-y-6">

        {/* Reference Image Upload */}
        <div 
          className={`bg-gray-900 p-6 rounded-xl border transition-colors duration-200 ${isDragging ? 'border-yellow-500 bg-gray-800' : 'border-gray-800'}`}
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          onDrop={handleDrop}
        >
          <h3 className="text-yellow-500 font-bold mb-4 flex items-center gap-2">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
            参考图片 (必填)
          </h3>

          {!refImage ? (
             <label className="flex flex-col items-center justify-center w-full h-48 border-2 border-gray-700 border-dashed rounded-lg cursor-pointer bg-gray-800 hover:bg-gray-750 transition-colors">
              <div className="flex flex-col items-center justify-center pt-5 pb-6">
                  <svg className="w-8 h-8 mb-4 text-gray-500" aria-hidden="true" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 20 16">
                      <path stroke="currentColor" strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 13h3a3 3 0 0 0 0-6h-.025A5.56 5.56 0 0 0 16 6.5 5.5 5.5 0 0 0 5.207 5.021C5.137 5.017 5.071 5 5 5a4 4 0 0 0 0 8h2.167M10 15V6m0 0L8 8m2-2 2 2"/>
                  </svg>
                  <p className="mb-2 text-sm text-gray-500"><span className="font-semibold">点击上传</span> 或拖拽图片</p>
                  <p className="text-xs text-gray-500">PNG, JPG (MAX. 10MB)</p>
              </div>
              <input type="file" className="hidden" accept="image/*" onChange={handleFileUpload} />
            </label>
          ) : (
            <div className="relative inline-block border border-gray-600 rounded-lg overflow-hidden group w-full flex justify-center bg-black/50">
              <img src={refImage} alt="Reference" className="h-64 object-contain" />
              <button 
                onClick={removeRefImage}
                className="absolute top-2 right-2 bg-red-600 text-white p-1 rounded hover:bg-red-700 shadow-lg"
                title="删除参考图"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
              </button>
            </div>
          )}
        </div>

        {/* Inputs */}
        <div className="bg-gray-900 p-6 rounded-xl border border-gray-800 space-y-4">

          {/* Main Prompt */}
          <div>
            <label className="text-sm font-semibold text-gray-400 uppercase tracking-wider block mb-2">
              生成描述 / 要求
            </label>
            <textarea 
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              className="w-full h-24 bg-gray-800 border border-gray-700 rounded-lg p-4 text-white focus:ring-2 focus:ring-yellow-500 outline-none resize-none"
              placeholder="请详细描述你想基于参考图生成的新内容，例如：'把图片中的猫变成赛博朋克风格的机器猫'..."
            ></textarea>
          </div>

          {/* Text Content Input */}
          <div className="pt-2 border-t border-gray-800">
             <label className="text-sm font-semibold text-gray-400 uppercase tracking-wider block mb-2 flex items-center gap-2">
               添加图片文本内容 <span className="text-xs bg-gray-700 text-gray-300 px-2 py-0.5 rounded-full font-normal">可选</span>
             </label>
             <input 
               type="text"
               value={textPrompt}
               onChange={(e) => setTextPrompt(e.target.value)}
               className="w-full bg-gray-800 border border-gray-700 rounded-lg px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none"
               placeholder="例如：'限时特惠' 或 'Happy Birthday'..."
             />
             <p className="text-xs text-gray-500 mt-2">若填写此项，Gemini 将尝试在画面中融合指定的文字内容。</p>
          </div>

        </div>

        {/* Configuration */}
        <div className="bg-gray-900 p-6 rounded-xl border border-gray-800 grid grid-cols-1 md:grid-cols-2 gap-6">
          <Select label="画幅比例 (默认保持原图)" value={aspectRatio} onChange={(e) => setAspectRatio(e.target.value as AspectRatio)}>
            <option value={AspectRatio.ORIGINAL}>原始尺寸 (智能匹配)</option>
            <option value={AspectRatio.PORTRAIT_3_4}>3:4 (人像/海报)</option>
            <option value={AspectRatio.PORTRAIT_4_5}>4:5 (社交媒体)</option>
            <option value={AspectRatio.SQUARE}>1:1 (正方形)</option>
            <option value={AspectRatio.PORTRAIT_9_16}>9:16 (手机全屏)</option>
            <option value={AspectRatio.LANDSCAPE_16_9}>16:9 (电影感)</option>
          </Select>

          <Select label="画质选择" value={quality} onChange={(e) => setQuality(e.target.value as ImageResolution)}>
            <option value={ImageResolution.RES_1K}>标准 (1K)</option>
            <option value={ImageResolution.RES_2K}>高清 (2K) - 仅 Pro</option>
          </Select>

          <div className="md:col-span-2">
            <Select label="生成数量" value={count} onChange={(e) => setCount(Number(e.target.value))}>
              <option value={1}>1 张</option>
              <option value={2}>2 张</option>
              <option value={3}>3 张</option>
              <option value={4}>4 张</option>
            </Select>
          </div>
        </div>

        {/* Action Button & Error */}
        <div>
          <Button 
            onClick={handleGenerate} 
            disabled={!refImage || (!prompt && !textPrompt)} 
            isLoading={isLoading} 
            className="w-full py-4 text-xl shadow-lg shadow-yellow-900/20"
          >
            🚀 开始重塑创作
          </Button>

          {error && (
            <div className="bg-red-900/50 border border-red-500 text-red-100 p-4 rounded-lg mt-4 animate-pulse">
               <h4 className="font-bold mb-1">❌ 生成失败</h4>
               <p className="text-sm opacity-90">{error}</p>
            </div>
          )}
        </div>
      </div>

      {/* Results Grid - Masonry-like layout without square forcing */}
      <div className="lg:w-2/5 bg-gray-900 rounded-xl border border-gray-800 p-6 overflow-y-auto max-h-[1200px]">
        <h3 className="text-yellow-500 font-bold mb-6 border-b border-gray-800 pb-2">创作成果</h3>
        <div className="columns-1 sm:columns-2 gap-4 space-y-4">
          {results.map((imgUrl, idx) => (
             <div key={idx} className="break-inside-avoid relative group rounded-xl overflow-hidden shadow-2xl bg-black border border-gray-700 mb-4">
                <img src={imgUrl} alt="Generated" className="w-full h-auto object-cover" />
                <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                   <a href={imgUrl} target="_blank" rel="noreferrer" className="bg-white/10 hover:bg-white/20 p-2 rounded-full backdrop-blur-sm text-white">
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"></path></svg>
                   </a>
                   <a href={imgUrl} download={`banana-pro-${Date.now()}.png`} className="bg-yellow-500 hover:bg-yellow-400 p-2 rounded-full text-black">
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path></svg>
                   </a>
                </div>
             </div>
          ))}
        </div>

        {results.length === 0 && !isLoading && (
          <div className="flex flex-col items-center justify-center text-gray-600 h-64 border-2 border-dashed border-gray-800 rounded-xl mt-10">
              <span className="text-4xl mb-2">🎨</span>
              <p>等待创作灵感...</p>
          </div>
        )}
        {isLoading && results.length === 0 && (
            <div className="flex items-center justify-center h-64 mt-10">
              <div className="animate-pulse text-yellow-500 font-mono">正在调用 Gemini 引擎...</div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { BananaModel, AspectRatio } from '../types';
import { editImageWithGemini } from '../services/geminiService';
import { Button } from './ui/Button';
import { Select } from './ui/Select';

interface Props {
  model: BananaModel;
}

export const TabSmartEdit: React.FC<Props> = ({ model }) => {
  const [image, setImage] = useState<string | null>(null);
  const [imageDimensions, setImageDimensions] = useState<{width: number, height: number} | null>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [brushSize, setBrushSize] = useState(20);
  const [prompt, setPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [resultImages, setResultImages] = useState<string[]>([]);

  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.ORIGINAL);
  const [activeTool, setActiveTool] = useState<'brush' | 'eraser' | 'rect' | 'none'>('none');
  const [isDragging, setIsDragging] = useState(false);

  // History for Undo
  const [history, setHistory] = useState<ImageData[]>([]);

  // Ref for the Start position of Box Select
  const dragStartRef = useRef<{x: number, y: number} | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Load image
  const loadImage = (src: string) => {
    const img = new Image();
    img.src = src;
    img.onload = () => {
      // Set dimensions
      setImage(src);
      setImageDimensions({ width: img.width, height: img.height });
      setHistory([]); 

      // Initialize canvas
      if (canvasRef.current) {
         canvasRef.current.width = img.width;
         canvasRef.current.height = img.height;
         const ctx = canvasRef.current.getContext('2d');
         ctx?.clearRect(0, 0, img.width, img.height);
         saveToHistory();
      }
    };
  };

  const saveToHistory = () => {
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (canvas && ctx) {
      const data = ctx.getImageData(0, 0, canvas.width, canvas.height);
      setHistory(prev => {
        const newHist = [...prev, data];
        if (newHist.length > 10) return newHist.slice(newHist.length - 10);
        return newHist;
      });
    }
  };

  const undo = () => {
    if (history.length <= 1) return;
    const newHistory = [...history];
    newHistory.pop(); // Remove current
    const previousState = newHistory[newHistory.length - 1];

    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (canvas && ctx && previousState) {
      ctx.putImageData(previousState, 0, 0);
      setHistory(newHistory);
    }
  };

  const validateAndSetImage = (file: File) => {
    if (file.size > 10 * 1024 * 1024) {
       setError("文件大小不能超过 10MB");
       return;
    }
    const reader = new FileReader();
    reader.onload = (evt) => {
      if (evt.target?.result) {
        loadImage(evt.target.result as string);
        setError(null);
        setResultImages([]);
      }
    };
    reader.readAsDataURL(file);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) validateAndSetImage(file);
  };

  // Drag & Drop Handlers
  const handleDragOver = (e: React.DragEvent) => { e.preventDefault(); setIsDragging(true); };
  const handleDragLeave = (e: React.DragEvent) => { e.preventDefault(); setIsDragging(false); };
  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files?.[0];
    if (file && file.type.startsWith('image/')) validateAndSetImage(file);
  };

  const clearCanvas = () => {
    setImage(null);
    setImageDimensions(null);
    setPrompt('');
    setResultImages([]);
    setError(null);
    setHistory([]);
    if (canvasRef.current) {
      const ctx = canvasRef.current.getContext('2d');
      ctx?.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
    }
  };

  // Improved Drawing logic using getBoundingClientRect for absolute precision
  const getCoordinates = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };

    // 1. Get the bounding box of the canvas on screen (CSS pixels)
    const rect = canvas.getBoundingClientRect();

    // 2. Calculate scaling factor (Internal Resolution / Display Size)
    // This handles any CSS scaling (max-width, etc.) perfectly
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;

    // 3. Calculate position relative to top-left of the canvas element, then scale to internal coordinates
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    return { x, y };
  };

  const startDrawing = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (activeTool === 'none' || !canvasRef.current) return;
    setIsDrawing(true);
    const coords = getCoordinates(e);

    if (activeTool === 'rect') {
      dragStartRef.current = coords;
      if (history.length === 0) saveToHistory();
    } else {
      const ctx = canvasRef.current.getContext('2d');
      if (ctx) {
        ctx.beginPath();
        ctx.moveTo(coords.x, coords.y);
        draw(e);
      }
    }
  };

  const stopDrawing = () => {
    if (isDrawing) {
      setIsDrawing(false);
      dragStartRef.current = null;
      const ctx = canvasRef.current?.getContext('2d');
      if (ctx) {
         ctx.beginPath();
         saveToHistory();
      }
    }
  };

  const draw = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!isDrawing || activeTool === 'none' || !canvasRef.current) return;

    const ctx = canvasRef.current.getContext('2d');
    if (!ctx) return;
    const { x, y } = getCoordinates(e);

    if (activeTool === 'rect') {
      if (!dragStartRef.current || history.length === 0) return;
      const lastState = history[history.length - 1];
      ctx.putImageData(lastState, 0, 0);

      ctx.globalCompositeOperation = 'source-over';
      ctx.fillStyle = 'rgba(255, 255, 255, 0.7)'; 
      const startX = dragStartRef.current.x;
      const startY = dragStartRef.current.y;
      ctx.fillRect(startX, startY, x - startX, y - startY);
      return;
    }

    ctx.lineWidth = brushSize;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    if (activeTool === 'eraser') {
      ctx.globalCompositeOperation = 'destination-out';
      ctx.strokeStyle = 'rgba(0,0,0,1)';
    } else {
      ctx.globalCompositeOperation = 'source-over'; 
      ctx.strokeStyle = 'rgba(255, 255, 255, 0.8)';
    }

    ctx.lineTo(x, y);
    ctx.stroke();
  };

  const getCalculatedAspectRatio = (model: BananaModel): AspectRatio => {
    if (aspectRatio !== AspectRatio.ORIGINAL) return aspectRatio;
    if (!imageDimensions) return AspectRatio.SQUARE;

    const currentRatio = imageDimensions.width / imageDimensions.height;

    const supported = [
      { id: AspectRatio.SQUARE, val: 1.0 },
      { id: AspectRatio.PORTRAIT_3_4, val: 0.75 },
      { id: AspectRatio.PORTRAIT_4_5, val: 0.8 },
      { id: AspectRatio.PORTRAIT_9_16, val: 0.5625 },
      { id: AspectRatio.LANDSCAPE_16_9, val: 1.777 },
    ];

    const closest = supported.reduce((prev, curr) => {
      return (Math.abs(curr.val - currentRatio) < Math.abs(prev.val - currentRatio) ? curr : prev);
    });

    return closest.id;
  };

  const handleGenerate = async (overridePrompt?: string, skipMask: boolean = false) => {
    if (!image) return;

    setIsLoading(true);
    setError(null);

    try {
      let maskBase64: string | undefined = undefined;

      if (!skipMask && canvasRef.current) {
        const maskCanvas = document.createElement('canvas');
        maskCanvas.width = canvasRef.current.width;
        maskCanvas.height = canvasRef.current.height;
        const mCtx = maskCanvas.getContext('2d');
        if (mCtx) {
          mCtx.fillStyle = '#000000';
          mCtx.fillRect(0, 0, maskCanvas.width, maskCanvas.height);
          mCtx.drawImage(canvasRef.current, 0, 0);
          maskBase64 = maskCanvas.toDataURL('image/png');
        }
      }

      const finalPrompt = overridePrompt || prompt;
      const finalAspectRatio = getCalculatedAspectRatio(model);

      const res = await editImageWithGemini({
        model,
        imageBase64: image, 
        maskBase64: skipMask ? undefined : maskBase64,
        prompt: finalPrompt,
        aspectRatio: finalAspectRatio,
      });

      setResultImages(res);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const handleCleanImage = () => {
    const cleanPrompt = "Clean up the image: remove all text, watermarks, subtitles, logos, icons, and UI elements. Preserve the original background, subject, and artistic style perfectly. Generate a high-resolution image that is 90% visually similar to the original but cleaner.";
    handleGenerate(cleanPrompt, true);
  };

  const presetAction = (actionPrompt: string, tool: 'brush' | 'none' = 'none') => {
    setPrompt(actionPrompt);
    if (tool !== 'none') setActiveTool(tool);
  };

  return (
    <div className="flex flex-col lg:flex-row gap-6 h-full">
      {/* Left: Canvas & Controls */}
      <div className="flex-1 flex flex-col gap-4">

        {/* Toolbar */}
        <div className="bg-gray-900 p-4 rounded-xl border border-gray-800 flex flex-wrap gap-3 items-center justify-between">
          <div className="flex gap-2">
            {!image && (
              <label className="cursor-pointer bg-yellow-500 hover:bg-yellow-400 text-gray-900 px-4 py-2 rounded-lg font-bold transition-colors">
                上传图片
                <input type="file" className="hidden" accept="image/*" onChange={handleFileUpload} />
              </label>
            )}

            {image && (
               <Button variant="danger" onClick={clearCanvas}>
                 删除 / 重置
               </Button>
            )}
          </div>

          {image && (
            <div className="flex gap-2 items-center flex-wrap">
              <div className="flex bg-gray-800 rounded-lg p-1 border border-gray-700">
                <button 
                  onClick={() => setActiveTool(activeTool === 'brush' ? 'none' : 'brush')}
                  className={`px-3 py-1.5 rounded text-sm font-medium transition-colors ${activeTool === 'brush' ? 'bg-indigo-600 text-white' : 'text-gray-400 hover:text-white'}`}
                  title="画笔"
                >
                  🖌️ 涂抹
                </button>
                 <button 
                  onClick={() => setActiveTool(activeTool === 'rect' ? 'none' : 'rect')}
                  className={`px-3 py-1.5 rounded text-sm font-medium transition-colors ${activeTool === 'rect' ? 'bg-indigo-600 text-white' : 'text-gray-400 hover:text-white'}`}
                  title="矩形选区"
                >
                  🔳 框选
                </button>
                <button 
                  onClick={() => setActiveTool(activeTool === 'eraser' ? 'none' : 'eraser')}
                  className={`px-3 py-1.5 rounded text-sm font-medium transition-colors ${activeTool === 'eraser' ? 'bg-pink-600 text-white' : 'text-gray-400 hover:text-white'}`}
                  title="橡皮擦"
                >
                  🧽 擦除
                </button>
              </div>

              <div className="border-l border-gray-700 mx-2 h-6"></div>

              <button 
                onClick={undo}
                disabled={history.length <= 1}
                className="px-3 py-1.5 bg-gray-800 hover:bg-gray-700 disabled:opacity-30 disabled:cursor-not-allowed border border-gray-700 rounded text-gray-300 text-sm"
                title="撤销"
              >
                ↩️ 撤销
              </button>

              {(activeTool === 'brush' || activeTool === 'eraser') && (
                <div className="flex items-center ml-2">
                   <span className="text-xs text-gray-400 mr-2">笔刷大小</span>
                   <input 
                    type="range" 
                    min="5" 
                    max="100" 
                    value={brushSize} 
                    onChange={(e) => setBrushSize(Number(e.target.value))}
                    className="w-24 accent-indigo-500 h-1.5 bg-gray-700 rounded-lg appearance-none cursor-pointer" 
                  />
                </div>
              )}
            </div>
          )}
        </div>

        {/* Canvas Area with Drag & Drop */}
        <div 
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          onDrop={handleDrop}
          className={`relative flex-1 bg-gray-900 rounded-xl border-2 flex items-center justify-center transition-colors duration-200 p-2
            ${isDragging ? 'border-yellow-500 bg-gray-800' : 'border-dashed border-gray-800'}
            ${!image ? 'cursor-pointer min-h-[400px]' : 'border-none bg-black/40'}
          `}
        >
          {/* Overlay for Drag instructions if no image */}
          {!image && (
             <div className="absolute inset-0 flex flex-col items-center justify-center text-gray-600 pointer-events-none">
               <svg className="w-12 h-12 mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
               <span>点击上传或拖入图片 (Max 10MB)</span>
             </div>
          )}

          {/* Invisible file input to allow clicking the empty box to upload */}
          {!image && (
            <input 
              type="file" 
              className="absolute inset-0 opacity-0 cursor-pointer w-full h-full z-20"
              accept="image/*"
              onChange={handleFileUpload}
            />
          )}

          {/* Wrapper for image + canvas to center them and let them determine size */}
          {image && (
            <div className="relative inline-block max-w-full max-h-full">
              {/* Layer 1: The Image (Bottom) */}
              <img 
                src={image} 
                alt="Source"
                className="block max-w-full max-h-[75vh] w-auto h-auto object-contain"
                style={{ pointerEvents: 'none' }} 
              />

              {/* Layer 2: The Mask Canvas (Top) - Absolute positioned to match img size exactly */}
              <canvas
                ref={canvasRef}
                onMouseDown={startDrawing}
                onMouseUp={stopDrawing}
                onMouseLeave={stopDrawing}
                onMouseMove={draw}
                className={`absolute top-0 left-0 w-full h-full object-contain ${image ? 'opacity-100' : 'opacity-0'} 
                  ${activeTool === 'brush' ? 'cursor-crosshair' : activeTool === 'eraser' ? 'cursor-cell' : activeTool === 'rect' ? 'cursor-crosshair' : 'cursor-default'}
                `}
              />
            </div>
          )}
        </div>

        {/* Action Panel */}
        <div className="bg-gray-800 p-6 rounded-xl space-y-4 border border-gray-700">

          {/* Main Action Grid */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
             {/* Text Input */}
             <div className="space-y-2">
                <label className="text-sm font-medium text-gray-300">修复指令 / 提示词</label>
                <input 
                  type="text" 
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder="例如：移除画面中的路人..." 
                  className="w-full bg-gray-900 border border-gray-600 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-yellow-500 outline-none"
                />
             </div>
             {/* Aspect Ratio */}
             <div>
               <Select label="智能扩图比例 (默认保持原图)" value={aspectRatio} onChange={(e) => setAspectRatio(e.target.value as AspectRatio)}>
                 <option value={AspectRatio.ORIGINAL}>原始尺寸 (智能裁切/扩展)</option>
                 <option value={AspectRatio.SQUARE}>1:1 (正方形)</option>
                 <option value={AspectRatio.PORTRAIT_4_5}>4:5 (社交媒体)</option>
                 <option value={AspectRatio.PORTRAIT_9_16}>9:16 (全面屏)</option>
                 <option value={AspectRatio.LANDSCAPE_16_9}>16:9 (宽屏)</option>
               </Select>
             </div>
          </div>

          <div className="flex flex-col md:flex-row gap-4 mt-2">
            <Button 
                onClick={() => handleGenerate()} 
                disabled={!image || !prompt} 
                isLoading={isLoading} 
                className="flex-1 py-3 text-lg"
              >
                ✨ 开始智能修图
            </Button>

            {/* New Clean Button */}
            <Button 
                onClick={handleCleanImage} 
                disabled={!image} 
                isLoading={isLoading} 
                variant="secondary"
                className="flex-1 py-3 text-lg border border-gray-600 bg-gray-800 hover:bg-gray-700 text-yellow-500"
              >
                🧼 一键清理 / 重绘
            </Button>
          </div>

          {/* Preset Chips */}
          <div className="flex flex-wrap gap-2 pt-2 border-t border-gray-700 mt-2">
            <span className="text-xs text-gray-500 uppercase font-bold py-1">预设指令:</span>
            <button onClick={() => presetAction("移除选区内的杂物", 'brush')} className="text-xs bg-gray-700 hover:bg-gray-600 px-3 py-1 rounded-full border border-gray-600">🧹 局部移除</button>
            <button onClick={() => presetAction("将背景替换为专业的绿幕背景", 'none')} className="text-xs bg-green-900/30 text-green-400 hover:bg-green-900/50 px-3 py-1 rounded-full border border-green-800">🟩 标准绿幕</button>
            <button onClick={() => presetAction("将背景替换为专业的蓝幕背景", 'none')} className="text-xs bg-blue-900/30 text-blue-400 hover:bg-blue-900/50 px-3 py-1 rounded-full border border-blue-800">🟦 标准蓝幕</button>
          </div>

          {error && (
            <div className="bg-red-900/50 border border-red-500 text-red-200 p-4 rounded-lg text-sm mt-2">
              <strong>生成失败：</strong> {error}
            </div>
          )}
        </div>
      </div>

      {/* Right: Results */}
      <div className="lg:w-1/3 bg-gray-900 rounded-xl border border-gray-800 p-4 flex flex-col gap-4 overflow-y-auto max-h-[800px]">
        <h3 className="text-lg font-bold text-yellow-500 mb-2 border-b border-gray-800 pb-2">生成结果</h3>
        <div className="grid grid-cols-1 gap-4">
          {resultImages.map((img, idx) => (
            <div key={idx} className="group relative rounded-lg overflow-hidden border border-gray-700 bg-black/50">
              <img src={img} alt={`Result ${idx}`} className="w-full h-auto object-contain max-h-[500px]" />
              <a 
                href={img} 
                download={`banana-edit-${Date.now()}.png`}
                className="absolute bottom-2 right-2 bg-black/70 hover:bg-black text-white px-3 py-1 rounded text-xs opacity-0 group-hover:opacity-100 transition-opacity"
              >
                下载
              </a>
            </div>
          ))}
          {resultImages.length === 0 && !isLoading && (
            <div className="text-gray-600 text-center py-10">
              暂无结果，请配置参数后点击生成
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { BananaModel, AspectRatio, ImageResolution } from '../types';
import { recreateImageWithGemini } from '../services/geminiService';
import { Button } from './ui/Button';
import { Select } from './ui/Select';

interface Props {
  model: BananaModel;
}

export const TabRecreate: React.FC<Props> = ({ model }) => {
  const [refImage, setRefImage] = useState<string | null>(null);
  const [imageDimensions, setImageDimensions] = useState<{width: number, height: number} | null>(null);

  const [prompt, setPrompt] = useState('');
  const [textPrompt, setTextPrompt] = useState(''); // New state for overlay text
  const [typographyInstruction, setTypographyInstruction] = useState(''); // New state for layout/style

  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.ORIGINAL);
  const [count, setCount] = useState(1);
  const [quality, setQuality] = useState<ImageResolution>(ImageResolution.RES_1K);

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<string[]>([]);
  const [isDragging, setIsDragging] = useState(false);

  const validateAndSetImage = (file: File) => {
    if (file.size > 10 * 1024 * 1024) {
      setError("文件大小不能超过 10MB");
      return;
    }
    const reader = new FileReader();
    reader.onload = (evt) => {
      const src = evt.target?.result as string;
      setRefImage(src);
      setError(null);
      // Load image to get dimensions
      const img = new Image();
      img.src = src;
      img.onload = () => {
        setImageDimensions({ width: img.width, height: img.height });
      };
    };
    reader.readAsDataURL(file);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) validateAndSetImage(file);
  };

  // Drag & Drop Handlers
  const handleDragOver = (e: React.DragEvent) => { e.preventDefault(); setIsDragging(true); };
  const handleDragLeave = (e: React.DragEvent) => { e.preventDefault(); setIsDragging(false); };
  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files?.[0];
    if (file && file.type.startsWith('image/')) {
      validateAndSetImage(file);
    }
  };

  const removeRefImage = () => {
    setRefImage(null);
    setImageDimensions(null);
  };

  const getCalculatedAspectRatio = (model: BananaModel): AspectRatio => {
    if (aspectRatio !== AspectRatio.ORIGINAL) return aspectRatio;
    if (!imageDimensions) return AspectRatio.SQUARE;

    const currentRatio = imageDimensions.width / imageDimensions.height;

    // Supported Ratios
    const supported = [
      { id: AspectRatio.SQUARE, val: 1.0 },
      { id: AspectRatio.PORTRAIT_3_4, val: 0.75 },
      { id: AspectRatio.PORTRAIT_4_5, val: 0.8 },
      { id: AspectRatio.PORTRAIT_9_16, val: 0.5625 },
      { id: AspectRatio.LANDSCAPE_16_9, val: 1.777 },
    ];

    const closest = supported.reduce((prev, curr) => {
      return (Math.abs(curr.val - currentRatio) < Math.abs(prev.val - currentRatio) ? curr : prev);
    });

    return closest.id;
  };

  const handleGenerate = async () => {
    if (!refImage || (!prompt && !textPrompt)) return;

    setIsLoading(true);
    setError(null);
    setResults([]);

    try {
      const finalAspectRatio = getCalculatedAspectRatio(model);

      let finalPrompt = prompt;

      // Merge logic if text content is provided
      if (textPrompt) {
        finalPrompt = `${prompt ? prompt + "\n\n" : ""}ADDITIONAL TASK: Add or Replace text in the image. \nText Content to render: "${textPrompt}".`;

        if (typographyInstruction) {
           finalPrompt += `\nTypography/Layout Instructions: ${typographyInstruction}`;
        }

        finalPrompt += `\nEnsure the typography matches the image style and follows the layout instructions.`;
      }

      const images = await recreateImageWithGemini({
        model,
        referenceImageBase64: refImage,
        prompt: finalPrompt,
        aspectRatio: finalAspectRatio,
        numberOfImages: count,
        quality
      });
      setResults(images);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8 h-full">
      {/* Control Panel */}
      <div className="flex-1 space-y-6">

        {/* Reference Image Upload */}
        <div 
          className={`bg-gray-900 p-6 rounded-xl border transition-colors duration-200 ${isDragging ? 'border-yellow-500 bg-gray-800' : 'border-gray-800'}`}
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          onDrop={handleDrop}
        >
          <h3 className="text-yellow-500 font-bold mb-4 flex items-center gap-2">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
            参考图片 (必填)
          </h3>

          {!refImage ? (
             <label className="flex flex-col items-center justify-center w-full h-48 border-2 border-gray-700 border-dashed rounded-lg cursor-pointer bg-gray-800 hover:bg-gray-750 transition-colors">
              <div className="flex flex-col items-center justify-center pt-5 pb-6">
                  <svg className="w-8 h-8 mb-4 text-gray-500" aria-hidden="true" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 20 16">
                      <path stroke="currentColor" strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 13h3a3 3 0 0 0 0-6h-.025A5.56 5.56 0 0 0 16 6.5 5.5 5.5 0 0 0 5.207 5.021C5.137 5.017 5.071 5 5 5a4 4 0 0 0 0 8h2.167M10 15V6m0 0L8 8m2-2 2 2"/>
                  </svg>
                  <p className="mb-2 text-sm text-gray-500"><span className="font-semibold">点击上传</span> 或拖拽图片</p>
                  <p className="text-xs text-gray-500">PNG, JPG (MAX. 10MB)</p>
              </div>
              <input type="file" className="hidden" accept="image/*" onChange={handleFileUpload} />
            </label>
          ) : (
            <div className="relative inline-block border border-gray-600 rounded-lg overflow-hidden group w-full flex justify-center bg-black/50">
              <img src={refImage} alt="Reference" className="h-64 object-contain" />
              <button 
                onClick={removeRefImage}
                className="absolute top-2 right-2 bg-red-600 text-white p-1 rounded hover:bg-red-700 shadow-lg"
                title="删除参考图"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
              </button>
            </div>
          )}
        </div>

        {/* Inputs */}
        <div className="bg-gray-900 p-6 rounded-xl border border-gray-800 space-y-4">

          {/* Main Prompt */}
          <div>
            <label className="text-sm font-semibold text-gray-400 uppercase tracking-wider block mb-2">
              生成描述 / 要求
            </label>
            <textarea 
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              className="w-full h-24 bg-gray-800 border border-gray-700 rounded-lg p-4 text-white focus:ring-2 focus:ring-yellow-500 outline-none resize-none"
              placeholder="请详细描述你想基于参考图生成的新内容，例如：'把图片中的猫变成赛博朋克风格的机器猫'..."
            ></textarea>
          </div>

          {/* Text Content Input */}
          <div className="pt-2 border-t border-gray-800">
             <label className="text-sm font-semibold text-gray-400 uppercase tracking-wider block mb-2 flex items-center gap-2">
               添加图片文本内容 <span className="text-xs bg-gray-700 text-gray-300 px-2 py-0.5 rounded-full font-normal">可选</span>
             </label>
             <input 
               type="text"
               value={textPrompt}
               onChange={(e) => setTextPrompt(e.target.value)}
               className="w-full bg-gray-800 border border-gray-700 rounded-lg px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none"
               placeholder="例如：'限时特惠' 或 'Happy Birthday'..."
             />

             {/* Typography Instruction */}
             {textPrompt && (
               <div className="mt-4 animate-in fade-in slide-in-from-top-1">
                 <label className="text-xs font-semibold text-gray-400 uppercase tracking-wider block mb-2 flex items-center gap-2">
                   文字排版与样式要求
                 </label>
                 <input 
                   type="text"
                   value={typographyInstruction}
                   onChange={(e) => setTypographyInstruction(e.target.value)}
                   className="w-full bg-gray-800 border border-gray-700 rounded-lg px-4 py-2 text-sm text-white focus:ring-2 focus:ring-blue-500 outline-none"
                   placeholder="例如：'使用白色手写体，居中放置在图片底部'..."
                 />
               </div>
             )}

             <p className="text-xs text-gray-500 mt-2">若填写此项，Gemini 将尝试在画面中融合指定的文字内容。</p>
          </div>

        </div>

        {/* Configuration */}
        <div className="bg-gray-900 p-6 rounded-xl border border-gray-800 grid grid-cols-1 md:grid-cols-2 gap-6">
          <Select label="画幅比例 (默认保持原图)" value={aspectRatio} onChange={(e) => setAspectRatio(e.target.value as AspectRatio)}>
            <option value={AspectRatio.ORIGINAL}>原始尺寸 (智能匹配)</option>
            <option value={AspectRatio.PORTRAIT_3_4}>3:4 (人像/海报)</option>
            <option value={AspectRatio.PORTRAIT_4_5}>4:5 (社交媒体)</option>
            <option value={AspectRatio.SQUARE}>1:1 (正方形)</option>
            <option value={AspectRatio.PORTRAIT_9_16}>9:16 (手机全屏)</option>
            <option value={AspectRatio.LANDSCAPE_16_9}>16:9 (电影感)</option>
          </Select>

          <Select label="画质选择" value={quality} onChange={(e) => setQuality(e.target.value as ImageResolution)}>
            <option value={ImageResolution.RES_1K}>标准 (1K)</option>
            <option value={ImageResolution.RES_2K}>高清 (2K) - 仅 Pro</option>
          </Select>

          <div className="md:col-span-2">
            <Select label="生成数量" value={count} onChange={(e) => setCount(Number(e.target.value))}>
              <option value={1}>1 张</option>
              <option value={2}>2 张</option>
              <option value={3}>3 张</option>
              <option value={4}>4 张</option>
            </Select>
          </div>
        </div>

        {/* Action Button & Error */}
        <div>
          <Button 
            onClick={handleGenerate} 
            disabled={!refImage || (!prompt && !textPrompt)} 
            isLoading={isLoading} 
            className="w-full py-4 text-xl shadow-lg shadow-yellow-900/20"
          >
            🚀 开始重塑创作
          </Button>

          {error && (
            <div className="bg-red-900/50 border border-red-500 text-red-100 p-4 rounded-lg mt-4 animate-pulse">
               <h4 className="font-bold mb-1">❌ 生成失败</h4>
               <p className="text-sm opacity-90">{error}</p>
            </div>
          )}
        </div>
      </div>

      {/* Results Grid - Masonry-like layout without square forcing */}
      <div className="lg:w-2/5 bg-gray-900 rounded-xl border border-gray-800 p-6 overflow-y-auto max-h-[1200px]">
        <h3 className="text-yellow-500 font-bold mb-6 border-b border-gray-800 pb-2">创作成果</h3>
        <div className="columns-1 sm:columns-2 gap-4 space-y-4">
          {results.map((imgUrl, idx) => (
             <div key={idx} className="break-inside-avoid relative group rounded-xl overflow-hidden shadow-2xl bg-black border border-gray-700 mb-4">
                <img src={imgUrl} alt="Generated" className="w-full h-auto object-cover" />
                <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                   <a href={imgUrl} target="_blank" rel="noreferrer" className="bg-white/10 hover:bg-white/20 p-2 rounded-full backdrop-blur-sm text-white">
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"></path></svg>
                   </a>
                   <a href={imgUrl} download={`banana-pro-${Date.now()}.png`} className="bg-yellow-500 hover:bg-yellow-400 p-2 rounded-full text-black">
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path></svg>
                   </a>
                </div>
             </div>
          ))}
        </div>

        {results.length === 0 && !isLoading && (
          <div className="flex flex-col items-center justify-center text-gray-600 h-64 border-2 border-dashed border-gray-800 rounded-xl mt-10">
              <span className="text-4xl mb-2">🎨</span>
              <p>等待创作灵感...</p>
          </div>
        )}
        {isLoading && results.length === 0 && (
            <div className="flex items-center justify-center h-64 mt-10">
              <div className="animate-pulse text-yellow-500 font-mono">正在调用 Gemini 引擎...</div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { BananaModel, AspectRatio } from '../types';
import { editImageWithGemini } from '../services/geminiService';
import { Button } from './ui/Button';
import { Select } from './ui/Select';

interface Props {
  model: BananaModel;
}

export const TabSmartEdit: React.FC<Props> = ({ model }) => {
  const [image, setImage] = useState<string | null>(null);
  const [imageDimensions, setImageDimensions] = useState<{width: number, height: number} | null>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [brushSize, setBrushSize] = useState(20);
  const [prompt, setPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [resultImages, setResultImages] = useState<string[]>([]);

  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.ORIGINAL);
  const [activeTool, setActiveTool] = useState<'brush' | 'eraser' | 'rect' | 'none'>('none');
  const [isDragging, setIsDragging] = useState(false);

  // History for Undo
  const [history, setHistory] = useState<ImageData[]>([]);

  // Ref for the Start position of Box Select
  const dragStartRef = useRef<{x: number, y: number} | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Load image
  const loadImage = (src: string) => {
    const img = new Image();
    img.src = src;
    img.onload = () => {
      // Set dimensions
      setImage(src);
      setImageDimensions({ width: img.width, height: img.height });
      setHistory([]); 

      // Initialize canvas
      if (canvasRef.current) {
         canvasRef.current.width = img.width;
         canvasRef.current.height = img.height;
         const ctx = canvasRef.current.getContext('2d');
         ctx?.clearRect(0, 0, img.width, img.height);
         saveToHistory();
      }
    };
  };

  const saveToHistory = () => {
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (canvas && ctx) {
      const data = ctx.getImageData(0, 0, canvas.width, canvas.height);
      setHistory(prev => {
        const newHist = [...prev, data];
        if (newHist.length > 10) return newHist.slice(newHist.length - 10);
        return newHist;
      });
    }
  };

  const undo = () => {
    if (history.length <= 1) return;
    const newHistory = [...history];
    newHistory.pop(); // Remove current
    const previousState = newHistory[newHistory.length - 1];

    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (canvas && ctx && previousState) {
      ctx.putImageData(previousState, 0, 0);
      setHistory(newHistory);
    }
  };

  const validateAndSetImage = (file: File) => {
    if (file.size > 10 * 1024 * 1024) {
       setError("文件大小不能超过 10MB");
       return;
    }
    const reader = new FileReader();
    reader.onload = (evt) => {
      if (evt.target?.result) {
        loadImage(evt.target.result as string);
        setError(null);
        setResultImages([]);
      }
    };
    reader.readAsDataURL(file);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) validateAndSetImage(file);
  };

  // Drag & Drop Handlers
  const handleDragOver = (e: React.DragEvent) => { e.preventDefault(); setIsDragging(true); };
  const handleDragLeave = (e: React.DragEvent) => { e.preventDefault(); setIsDragging(false); };
  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files?.[0];
    if (file && file.type.startsWith('image/')) validateAndSetImage(file);
  };

  const clearCanvas = () => {
    setImage(null);
    setImageDimensions(null);
    setPrompt('');
    setResultImages([]);
    setError(null);
    setHistory([]);
    if (canvasRef.current) {
      const ctx = canvasRef.current.getContext('2d');
      ctx?.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
    }
  };

  // Robust Coordinate Calculation using Pointer Events
  const getCoordinates = (e: React.PointerEvent<HTMLCanvasElement>) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };

    // Scale factor: Internal Resolution / Displayed CSS Size
    // offsetX/Y gives position relative to the element's padding box, which is perfect for us
    const scaleX = canvas.width / canvas.clientWidth;
    const scaleY = canvas.height / canvas.clientHeight;

    return {
      x: e.nativeEvent.offsetX * scaleX,
      y: e.nativeEvent.offsetY * scaleY
    };
  };

  const startDrawing = (e: React.PointerEvent<HTMLCanvasElement>) => {
    if (activeTool === 'none' || !canvasRef.current) return;

    // Capture pointer to ensure we track movement even if mouse leaves canvas bounds slightly
    e.currentTarget.setPointerCapture(e.pointerId);

    setIsDrawing(true);
    const coords = getCoordinates(e);

    if (activeTool === 'rect') {
      dragStartRef.current = coords;
      if (history.length === 0) saveToHistory();
    } else {
      const ctx = canvasRef.current.getContext('2d');
      if (ctx) {
        ctx.beginPath();
        ctx.moveTo(coords.x, coords.y);
        draw(e);
      }
    }
  };

  const stopDrawing = (e: React.PointerEvent<HTMLCanvasElement>) => {
    if (isDrawing) {
      e.currentTarget.releasePointerCapture(e.pointerId);
      setIsDrawing(false);
      dragStartRef.current = null;
      const ctx = canvasRef.current?.getContext('2d');
      if (ctx) {
         ctx.beginPath();
         saveToHistory();
      }
    }
  };

  const draw = (e: React.PointerEvent<HTMLCanvasElement>) => {
    if (!isDrawing || activeTool === 'none' || !canvasRef.current) return;

    const ctx = canvasRef.current.getContext('2d');
    if (!ctx) return;
    const { x, y } = getCoordinates(e);

    if (activeTool === 'rect') {
      if (!dragStartRef.current || history.length === 0) return;
      const lastState = history[history.length - 1];
      ctx.putImageData(lastState, 0, 0);

      ctx.globalCompositeOperation = 'source-over';
      ctx.fillStyle = 'rgba(255, 255, 255, 0.7)'; 
      const startX = dragStartRef.current.x;
      const startY = dragStartRef.current.y;
      ctx.fillRect(startX, startY, x - startX, y - startY);
      return;
    }

    ctx.lineWidth = brushSize;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    if (activeTool === 'eraser') {
      ctx.globalCompositeOperation = 'destination-out';
      ctx.strokeStyle = 'rgba(0,0,0,1)';
    } else {
      ctx.globalCompositeOperation = 'source-over'; 
      ctx.strokeStyle = 'rgba(255, 255, 255, 0.8)';
    }

    ctx.lineTo(x, y);
    ctx.stroke();
  };

  const getCalculatedAspectRatio = (model: BananaModel): AspectRatio => {
    if (aspectRatio !== AspectRatio.ORIGINAL) return aspectRatio;
    if (!imageDimensions) return AspectRatio.SQUARE;

    const currentRatio = imageDimensions.width / imageDimensions.height;

    const supported = [
      { id: AspectRatio.SQUARE, val: 1.0 },
      { id: AspectRatio.PORTRAIT_3_4, val: 0.75 },
      { id: AspectRatio.PORTRAIT_4_5, val: 0.8 },
      { id: AspectRatio.PORTRAIT_9_16, val: 0.5625 },
      { id: AspectRatio.LANDSCAPE_16_9, val: 1.777 },
    ];

    const closest = supported.reduce((prev, curr) => {
      return (Math.abs(curr.val - currentRatio) < Math.abs(prev.val - currentRatio) ? curr : prev);
    });

    return closest.id;
  };

  const handleGenerate = async (overridePrompt?: string, skipMask: boolean = false) => {
    if (!image) return;

    setIsLoading(true);
    setError(null);

    try {
      let maskBase64: string | undefined = undefined;

      if (!skipMask && canvasRef.current) {
        const maskCanvas = document.createElement('canvas');
        maskCanvas.width = canvasRef.current.width;
        maskCanvas.height = canvasRef.current.height;
        const mCtx = maskCanvas.getContext('2d');
        if (mCtx) {
          mCtx.fillStyle = '#000000';
          mCtx.fillRect(0, 0, maskCanvas.width, maskCanvas.height);
          mCtx.drawImage(canvasRef.current, 0, 0);
          maskBase64 = maskCanvas.toDataURL('image/png');
        }
      }

      const finalPrompt = overridePrompt || prompt;
      const finalAspectRatio = getCalculatedAspectRatio(model);

      const res = await editImageWithGemini({
        model,
        imageBase64: image, 
        maskBase64: skipMask ? undefined : maskBase64,
        prompt: finalPrompt,
        aspectRatio: finalAspectRatio,
      });

      setResultImages(res);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const handleCleanImage = () => {
    const cleanPrompt = "Clean up the image: remove all text, watermarks, subtitles, logos, icons, and UI elements. Preserve the original background, subject, and artistic style perfectly. Generate a high-resolution image that is 90% visually similar to the original but cleaner.";
    handleGenerate(cleanPrompt, true);
  };

  const presetAction = (actionPrompt: string, tool: 'brush' | 'none' = 'none') => {
    setPrompt(actionPrompt);
    if (tool !== 'none') setActiveTool(tool);
  };

  return (
    <div className="flex flex-col lg:flex-row gap-6 h-full">
      {/* Left: Canvas & Controls */}
      <div className="flex-1 flex flex-col gap-4">

        {/* Toolbar */}
        <div className="bg-gray-900 p-4 rounded-xl border border-gray-800 flex flex-wrap gap-3 items-center justify-between">
          <div className="flex gap-2">
            {!image && (
              <label className="cursor-pointer bg-yellow-500 hover:bg-yellow-400 text-gray-900 px-4 py-2 rounded-lg font-bold transition-colors">
                上传图片
                <input type="file" className="hidden" accept="image/*" onChange={handleFileUpload} />
              </label>
            )}

            {image && (
               <Button variant="danger" onClick={clearCanvas}>
                 删除 / 重置
               </Button>
            )}
          </div>

          {image && (
            <div className="flex gap-2 items-center flex-wrap">
              <div className="flex bg-gray-800 rounded-lg p-1 border border-gray-700">
                <button 
                  onClick={() => setActiveTool(activeTool === 'brush' ? 'none' : 'brush')}
                  className={`px-3 py-1.5 rounded text-sm font-medium transition-colors ${activeTool === 'brush' ? 'bg-indigo-600 text-white' : 'text-gray-400 hover:text-white'}`}
                  title="画笔"
                >
                  🖌️ 涂抹
                </button>
                 <button 
                  onClick={() => setActiveTool(activeTool === 'rect' ? 'none' : 'rect')}
                  className={`px-3 py-1.5 rounded text-sm font-medium transition-colors ${activeTool === 'rect' ? 'bg-indigo-600 text-white' : 'text-gray-400 hover:text-white'}`}
                  title="矩形选区"
                >
                  🔳 框选
                </button>
                <button 
                  onClick={() => setActiveTool(activeTool === 'eraser' ? 'none' : 'eraser')}
                  className={`px-3 py-1.5 rounded text-sm font-medium transition-colors ${activeTool === 'eraser' ? 'bg-pink-600 text-white' : 'text-gray-400 hover:text-white'}`}
                  title="橡皮擦"
                >
                  🧽 擦除
                </button>
              </div>

              <div className="border-l border-gray-700 mx-2 h-6"></div>

              <button 
                onClick={undo}
                disabled={history.length <= 1}
                className="px-3 py-1.5 bg-gray-800 hover:bg-gray-700 disabled:opacity-30 disabled:cursor-not-allowed border border-gray-700 rounded text-gray-300 text-sm"
                title="撤销"
              >
                ↩️ 撤销
              </button>

              {(activeTool === 'brush' || activeTool === 'eraser') && (
                <div className="flex items-center ml-2">
                   <span className="text-xs text-gray-400 mr-2">笔刷大小</span>
                   <input 
                    type="range" 
                    min="5" 
                    max="100" 
                    value={brushSize} 
                    onChange={(e) => setBrushSize(Number(e.target.value))}
                    className="w-24 accent-indigo-500 h-1.5 bg-gray-700 rounded-lg appearance-none cursor-pointer" 
                  />
                </div>
              )}
            </div>
          )}
        </div>

        {/* Canvas Area with Drag & Drop */}
        <div 
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          onDrop={handleDrop}
          className={`relative flex-1 bg-gray-900 rounded-xl border-2 flex items-center justify-center transition-colors duration-200 p-2
            ${isDragging ? 'border-yellow-500 bg-gray-800' : 'border-dashed border-gray-800'}
            ${!image ? 'cursor-pointer min-h-[400px]' : 'border-none bg-black/40'}
          `}
        >
          {!image && (
             <div className="absolute inset-0 flex flex-col items-center justify-center text-gray-600 pointer-events-none">
               <svg className="w-12 h-12 mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
               <span>点击上传或拖入图片 (Max 10MB)</span>
             </div>
          )}

          {!image && (
            <input 
              type="file" 
              className="absolute inset-0 opacity-0 cursor-pointer w-full h-full z-20"
              accept="image/*"
              onChange={handleFileUpload}
            />
          )}

          {/* Wrapper for image + canvas to center them and let them determine size */}
          {image && (
            <div className="relative inline-block max-w-full max-h-full">
              {/* Layer 1: The Image (Bottom) */}
              <img 
                src={image} 
                alt="Source"
                className="block max-w-full max-h-[75vh] w-auto h-auto object-contain"
                style={{ pointerEvents: 'none' }} 
              />

              {/* Layer 2: The Mask Canvas (Top) - Absolute positioned to match img size exactly */}
              <canvas
                ref={canvasRef}
                onPointerDown={startDrawing}
                onPointerUp={stopDrawing}
                onPointerLeave={stopDrawing}
                onPointerMove={draw}
                className={`absolute inset-0 w-full h-full ${image ? 'opacity-100' : 'opacity-0'} touch-none
                  ${activeTool === 'brush' ? 'cursor-crosshair' : activeTool === 'eraser' ? 'cursor-cell' : activeTool === 'rect' ? 'cursor-crosshair' : 'cursor-default'}
                `}
              />
            </div>
          )}
        </div>

        {/* Action Panel */}
        <div className="bg-gray-800 p-6 rounded-xl space-y-4 border border-gray-700">

          {/* Main Action Grid */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
             {/* Text Input */}
             <div className="space-y-2">
                <label className="text-sm font-medium text-gray-300">修复指令 / 提示词</label>
                <input 
                  type="text" 
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder="例如：移除画面中的路人..." 
                  className="w-full bg-gray-900 border border-gray-600 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-yellow-500 outline-none"
                />
             </div>
             {/* Aspect Ratio */}
             <div>
               <Select label="智能扩图比例 (默认保持原图)" value={aspectRatio} onChange={(e) => setAspectRatio(e.target.value as AspectRatio)}>
                 <option value={AspectRatio.ORIGINAL}>原始尺寸 (智能裁切/扩展)</option>
                 <option value={AspectRatio.SQUARE}>1:1 (正方形)</option>
                 <option value={AspectRatio.PORTRAIT_4_5}>4:5 (社交媒体)</option>
                 <option value={AspectRatio.PORTRAIT_9_16}>9:16 (全面屏)</option>
                 <option value={AspectRatio.LANDSCAPE_16_9}>16:9 (宽屏)</option>
               </Select>
             </div>
          </div>

          <div className="flex flex-col md:flex-row gap-4 mt-2">
            <Button 
                onClick={() => handleGenerate()} 
                disabled={!image || !prompt} 
                isLoading={isLoading} 
                className="flex-1 py-3 text-lg"
              >
                ✨ 开始智能修图
            </Button>

            {/* New Clean Button */}
            <Button 
                onClick={handleCleanImage} 
                disabled={!image} 
                isLoading={isLoading} 
                variant="secondary"
                className="flex-1 py-3 text-lg border border-gray-600 bg-gray-800 hover:bg-gray-700 text-yellow-500"
              >
                🧼 一键清理 / 重绘
            </Button>
